INSERT INTO `mock_examination_part` VALUES (95, 3, 30, 1, NULL, 1, 30, 30, NULL, '口语第三部分', '{\"cn\": \"口语第三部分\", \"de\": \"Speaking: Part 3\", \"en\": \"Speaking: Part 3\", \"fr\": \"Oral: Partie 3\", \"hu\": \"Speaking: Part 3\", \"id\": \"Speaking: Part 3\", \"ko\": \"Speaking: Part 3\", \"mn\": \"Яриа гуравдугаар хэсэг\", \"ru\": \"Говоря, часть 3\", \"th\": \"การพูด: ส่วนที่ 3\", \"vi\": \"Khẩu ngữ: Phần 3\", \"ja\": \"話し言葉：第三部分\", \"ar\": \"الجزء الثالث من المحادثة\", \"zh\": \"口语第三部分\", \"bg\": \"Разговорен (Трета част)\"}', 0, '2024-05-15 15:05:49', '2024-05-15 15:05:49');
INSERT INTO `mock_examination_part` VALUES (96, 1, 31, 15, NULL, 15, 2, 30, NULL, '口语第一部分【听后重复】', '{\"cn\": \"听后重复\", \"de\": \"Wiederholen sie den bericht.\", \"en\": \"Repeat after listening\", \"fr\": \"Répéter après avoir écouté\", \"hu\": \"Hallgassa meg és ismételje meg\", \"id\": \"Ulangi setelah mendengarkan\", \"ko\": \"들은 후에 반복하다.\", \"mn\": \"Сонсож, давт\", \"ru\": \"Повторение услышанного.\", \"th\": \"ย้ำหลังจากได้ยิน\", \"vi\": \"Sau khi nghe nhắc lại\", \"ja\": \"後述を聞く\", \"ar\": \"إعادة التكرار بعد الاستماع\", \"zh\": \"听后重复\", \"bg\": \"Чуйте и повторете\"}', 0, '2024-05-17 10:54:21', '2024-05-17 10:54:21');
INSERT INTO `mock_examination_part` VALUES (97, 2, 31, 10, NULL, 10, 3, 30, NULL, '口语第二部分【听后回答】', '{\"cn\": \"听后回答\", \"de\": \"Antworten sie nach dem zuhören.\", \"en\": \"Listen and answer\", \"fr\": \"Répondre après avoir écouté\", \"hu\": \"Hallgassa meg és válaszoljon\", \"id\": \"Jawab setelah mendengarkan\", \"ko\": \"S듣고 대답하다\", \"mn\": \"Сонсосны дараа хариулна уу\", \"ru\": \"Ответ на вопросы после прослушивания.\", \"th\": \"ตอบด้วย\", \"vi\": \"Sau khi nghe câu trả lời\", \"ja\": \"聞いて答える\", \"ar\": \"الرد بعد الاستماع\", \"zh\": \"听后回答\", \"bg\": \"Oтговорете след слушане\"}', 0, '2024-05-17 10:54:21', '2024-05-17 10:54:21');
INSERT INTO `mock_examination_part` VALUES (98, 3, 31, 2, NULL, 2, 20, 40, NULL, '口语第三部分【回答问题】', '{\"cn\": \"回答问题\", \"de\": \"Beantworte meine frage\", \"en\": \"Answer the question\", \"fr\": \"Répondre aux questions\", \"hu\": \"Válaszoljon a kérdésre\", \"id\": \"Jawab pertanyaan\", \"ko\": \"문제에 대답하다\", \"mn\": \"асуултуудад хариулна уу\", \"ru\": \"Ответы на вопросы\", \"th\": \"ตอบคำถาม\", \"vi\": \"Trả lời câu hỏi\", \"ja\": \"質問に答える\", \"ar\": \"الإجابة عن الأسئلة\", \"zh\": \"回答问题\", \"bg\": \"Oтговорете на въпросите\"}', 0, '2024-05-17 10:54:21', '2024-05-17 10:54:21');
INSERT INTO `mock_examination_part` VALUES (99, 1, 32, 10, NULL, 10, 3, 30, NULL, '口语第一部分【听后重复】', '{\"cn\": \"听后重复\", \"de\": \"Wiederholen sie den bericht.\", \"en\": \"Repeat after listening\", \"fr\": \"Répéter après avoir écouté\", \"hu\": \"Hallgassa meg és ismételje meg\", \"id\": \"Ulangi setelah mendengarkan\", \"ko\": \"들은 후에 반복하다.\", \"mn\": \"Сонсож, давт\", \"ru\": \"Повторение услышанного.\", \"th\": \"ย้ำหลังจากได้ยิน\", \"vi\": \"Sau khi nghe nhắc lại\", \"ja\": \"後述を聞く\", \"ar\": \"إعادة التكرار بعد الاستماع\", \"zh\": \"听后重复\", \"bg\": \"Чуйте и повторете\"}', 0, '2024-05-17 11:06:04', '2024-05-17 11:06:04');
INSERT INTO `mock_examination_part` VALUES (100, 2, 32, 2, NULL, 2, 15, 30, NULL, '口语第二部分【看图说话】', '{\"cn\": \"看图说话\", \"de\": \"Schau hinauf\", \"en\": \"Look at pictures and speak\", \"fr\": \"Voir l’image parler\", \"hu\": \"Nézd meg a képet, és beszélj\", \"id\": \"Lihat bicara\", \"ko\": \"그림을 보고 말하다\", \"mn\": \"Зургийн яриа\", \"ru\": \"Смотрите фотографии и поговорите\", \"th\": \"ลองดูสิ\", \"vi\": \"Xem hình ảnh nói chuyện\", \"ja\": \"図を見て話す\", \"ar\": \"التحدث عن الصورة\", \"zh\": \"看图说话\", \"bg\": \"Разказвай по картинки\"}', 0, '2024-05-17 11:06:04', '2024-05-17 11:06:04');
INSERT INTO `mock_examination_part` VALUES (101, 3, 32, 2, NULL, 2, 20, 40, NULL, '口语第三部分【回答问题】', '{\"cn\": \"回答问题\", \"de\": \"Beantworte meine frage\", \"en\": \"Answer the question\", \"fr\": \"Répondre aux questions\", \"hu\": \"Válaszoljon a kérdésre\", \"id\": \"Jawab pertanyaan\", \"ko\": \"문제에 대답하다\", \"mn\": \"асуултуудад хариулна уу\", \"ru\": \"Ответы на вопросы\", \"th\": \"ตอบคำถาม\", \"vi\": \"Trả lời câu hỏi\", \"ja\": \"質問に答える\", \"ar\": \"الإجابة عن الأسئلة\", \"zh\": \"回答问题\", \"bg\": \"Oтговорете на въпросите\"}', 0, '2024-05-17 11:06:05', '2024-05-17 11:06:05');
INSERT INTO `mock_examination_part` VALUES (102, 1, 33, 3, NULL, 3, 10, 20, NULL, '口语第一部分【听后复述】', '{\"cn\": \"听后复述\", \"de\": \"Hören, vorlesen\", \"en\": \"Listen and repeat\", \"fr\": \"Récit après écoute\", \"hu\": \"Hallgasd meg és ismételd meg\", \"id\": \"Ulangi setelah mendengarkan\", \"ko\": \"들은 후 다시 말하다.\", \"mn\": \"Сонссоныхоо дараа дахин ярь\", \"ru\": \"Слушайте и повторяйте\", \"th\": \"พูดอีกครั้งหลังจากฟัง\", \"vi\": \"Kể lại sau khi nghe\", \"ja\": \"後述を聞く\", \"ar\": \"إعادة السرد بعد الاستماع\", \"zh\": \"听后复述\", \"bg\": \"Чуйте и повторете\"}', 0, '2024-05-17 11:06:31', '2024-05-17 11:06:31');
INSERT INTO `mock_examination_part` VALUES (103, 2, 33, 1, NULL, 1, 20, 60, NULL, '口语第二部分【朗读】', '{\"cn\": \"朗读\", \"de\": \"Lies vor\", \"en\": \"Read aloud\", \"fr\": \"lire\", \"hu\": \"felolvas\", \"id\": \"Dengan suara keras\", \"ko\": \"낭독\", \"mn\": \"Чанга унш\", \"ru\": \"Чтение вслух\", \"th\": \"อ่านออกเสียง\", \"vi\": \"đọc\", \"ja\": \"朗読\", \"ar\": \"القراءة\", \"zh\": \"朗读\", \"bg\": \"Прочетете на глас\"}', 0, '2024-05-17 11:06:31', '2024-05-17 11:06:31');
INSERT INTO `mock_examination_part` VALUES (104, 3, 33, 2, NULL, 2, 25, 40, NULL, '口语第三部分【回答问题】', '{\"cn\": \"回答问题\", \"de\": \"Beantworte meine frage\", \"en\": \"Answer the question\", \"fr\": \"Répondre aux questions\", \"hu\": \"Válaszoljon a kérdésre\", \"id\": \"Jawab pertanyaan\", \"ko\": \"문제에 대답하다\", \"mn\": \"асуултуудад хариулна уу\", \"ru\": \"Ответы на вопросы\", \"th\": \"ตอบคำถาม\", \"vi\": \"Trả lời câu hỏi\", \"ja\": \"質問に答える\", \"ar\": \"الإجابة عن الأسئلة\", \"zh\": \"回答问题\", \"bg\": \"Oтговорете на въпросите\"}', 0, '2024-05-17 11:06:31', '2024-05-17 11:06:31');
