INSERT INTO `mock_examination_part` VALUES (167, 3, 55, 1, NULL, 1, 30, 30, NULL, '口语第三部分', '{\"cn\": \"口语第三部分\", \"de\": \"Speaking: Part 3\", \"en\": \"Speaking: Part 3\", \"fr\": \"Oral: Partie 3\", \"hu\": \"Speaking: Part 3\", \"id\": \"Speaking: Part 3\", \"ko\": \"Speaking: Part 3\", \"mn\": \"Яриа гуравдугаар хэсэг\", \"ru\": \"Говоря, часть 3\", \"th\": \"การพูด: ส่วนที่ 3\", \"vi\": \"Khẩu ngữ: Phần 3\", \"ja\": \"話し言葉：第三部分\", \"ar\": \"الجزء الثالث من المحادثة\", \"zh\": \"口语第三部分\", \"bg\": \"Разговорен (Трета част)\"}', 0, '2026-01-23 21:02:23', '2026-01-23 21:02:23');
INSERT INTO `mock_examination_part` VALUES (168, 1, 56, 8, NULL, 8, 3.125, 25, NULL, '口语第一部分【听后重复】', '{\"cn\": \"听后重复\", \"de\": \"Wiederholen sie den bericht.\", \"en\": \"Repeat after listening\", \"fr\": \"Répéter après avoir écouté\", \"hu\": \"Hallgassa meg és ismételje meg\", \"id\": \"Ulangi setelah mendengarkan\", \"ko\": \"들은 후에 반복하다.\", \"mn\": \"Сонсож, давт\", \"ru\": \"Повторение услышанного.\", \"th\": \"ย้ำหลังจากได้ยิน\", \"vi\": \"Sau khi nghe nhắc lại\", \"ja\": \"後述を聞く\", \"ar\": \"إعادة التكرار بعد الاستماع\", \"zh\": \"听后重复\", \"bg\": \"Чуйте и повторете\"}', 0, '2024-05-17 11:06:04', '2024-05-17 11:06:04');
INSERT INTO `mock_examination_part` VALUES (169, 2, 56, 5, NULL, 5, 7, 35, NULL, '口语第二部分【看图说话】', '{\"cn\": \"看图说话\", \"de\": \"Schau hinauf\", \"en\": \"Look at pictures and speak\", \"fr\": \"Voir l’image parler\", \"hu\": \"Nézd meg a képet, és beszélj\", \"id\": \"Lihat bicara\", \"ko\": \"그림을 보고 말하다\", \"mn\": \"Зургийн яриа\", \"ru\": \"Смотрите фотографии и поговорите\", \"th\": \"ลองดูสิ\", \"vi\": \"Xem hình ảnh nói chuyện\", \"ja\": \"図を見て話す\", \"ar\": \"التحدث عن الصورة\", \"zh\": \"看图说话\", \"bg\": \"Разказвай по картинки\"}', 0, '2026-01-05 19:46:53', '2026-01-05 19:46:53');
INSERT INTO `mock_examination_part` VALUES (170, 3, 56, 2, NULL, 2, 20, 40, NULL, '口语第三部分【回答问题】', '{\"cn\": \"回答问题\", \"de\": \"Beantworte meine frage\", \"en\": \"Answer the question\", \"fr\": \"Répondre aux questions\", \"hu\": \"Válaszoljon a kérdésre\", \"id\": \"Jawab pertanyaan\", \"ko\": \"문제에 대답하다\", \"mn\": \"асуултуудад хариулна уу\", \"ru\": \"Ответы на вопросы\", \"th\": \"ตอบคำถาม\", \"vi\": \"Trả lời câu hỏi\", \"ja\": \"質問に答える\", \"ar\": \"الإجابة عن الأسئلة\", \"zh\": \"回答问题\", \"bg\": \"Oтговорете на въпросите\"}', 0, '2026-01-05 19:48:09', '2026-01-05 19:48:09');
INSERT INTO `mock_examination_part` VALUES (171, 1, 57, 2, NULL, 2, 15, 30, NULL, '口语第一部分【听后复述】', '{\"cn\": \"听后复述\", \"de\": \"Hören, vorlesen\", \"en\": \"Listen and repeat\", \"fr\": \"Récit après écoute\", \"hu\": \"Hallgasd meg és ismételd meg\", \"id\": \"Ulangi setelah mendengarkan\", \"ko\": \"들은 후 다시 말하다.\", \"mn\": \"Сонссоныхоо дараа дахин ярь\", \"ru\": \"Слушайте и повторяйте\", \"th\": \"พูดอีกครั้งหลังจากฟัง\", \"vi\": \"Kể lại sau khi nghe\", \"ja\": \"後述を聞く\", \"ar\": \"إعادة السرد بعد الاستماع\", \"zh\": \"听后复述\", \"bg\": \"Чуйте и повторете\"}', 0, '2024-05-17 11:06:04', '2024-05-17 11:06:04');
