INSERT INTO `mock_examination_segment` VALUES (26, 12, 'listen', '听力', '{\"cn\": \"听力\", \"en\": \"Listening\", \"fr\": \"Compréhension orale\", \"ja\": \"聞き取り\", \"ko\": \"Listening\", \"mn\": \"Сонсгол\", \"ru\": \"Аудирование\", \"th\": \"การฟัง\", \"vi\": \"Kỹ năng nghe\", \"zh\": \"听力\", \"ar\": \"الاستماع\", \"bg\": \"Слушане\"}', '{\"cn\": \"包括新闻报道、商务谈判、辩论、采访、演讲/讲座、纪录片、会议发言等。\", \"en\": \"Includes news reports, business negotiations, debates, interviews, speeches/lectures, documentaries, conference speeches, etc.\", \"fr\": \"Inclut des reportages, des négociations commerciales, des débats, des interviews, des discours/conférences, des documentaires, des discours de conférence, etc.\", \"ja\": \"Includes news reports, business negotiations, debates, interviews, speeches/lectures, documentaries, conference speeches, etc.\", \"ko\": \"Includes news reports, business negotiations, debates, interviews, speeches/lectures, documentaries, conference speeches, etc.\", \"mn\": \"Мэдээ, бизнес хэлэлцээр, мэтгэлцээн, ярилцлага, илтгэл/лекц, баримтат кино, хурлын үг зэрэг багтана\", \"ru\": \"Includes news reports, business negotiations, debates, interviews, speeches/lectures, documentaries, conference speeches, etc.\", \"th\": \"ประกอบด้วยรายงานข่าว การเจรจาธุรกิจ การอภิปราย การสัมภาษณ์ การกล่าวสุนทรพจน์/การบรรยาย สารคดี การกล่าวสุนทรพจน์ในการประชุม ฯลฯ\", \"vi\": \"Bao gồm các bản tin, đàm phán kinh doanh, tranh luận, phỏng vấn, bài phát biểu/bài giảng, phim tài liệu, bài phát biểu hội nghị, v.v.\", \"zh\": \"包括新闻报道、商务谈判、辩论、采访、演讲/讲座、纪录片、会议发言等。\"}', 100, 40, 30, 1, 0, '2024-05-15 14:26:58', '2024-05-15 14:26:58');
INSERT INTO `mock_examination_segment` VALUES (27, 12, 'read', '阅读', '{\"cn\": \"阅读\", \"en\": \"Reading\", \"fr\": \"Lecture\", \"ja\": \"読解\", \"ko\": \"Reading\", \"mn\": \"Унших\", \"ru\": \"Чтение\", \"th\": \"การอ่าน\", \"vi\": \"Kỹ năng đọc hiểu\", \"zh\": \"阅读\", \"ar\": \"القراءة\", \"bg\": \"Четене \"}', '{\"cn\": \"包括新闻报道、科普文章、调查报告、学术文献、中华文化及中国概况等。\", \"en\": \"Involves news reports, scientific articles, survey reports, academic literature, Chinese culture, and overview of China.\", \"fr\": \"Implique des reportages, des articles scientifiques, des rapports d\'enquête, de la littérature académique, la culture chinoise et une vue d\'ensemble de la Chine.\", \"ja\": \"Involves news reports, scientific articles, survey reports, academic literature, Chinese culture, and overview of China.\", \"ko\": \"Involves news reports, scientific articles, survey reports, academic literature, Chinese culture, and overview of China.\", \"mn\": \"Мэдээ, танин мэдэхүйн нийтлэл, судалгааны тайлан, эрдэм шинжилгээний нийтлэл, хятад соёл, хятадын тойм зэрэг багтана\", \"ru\": \"Involves news reports, scientific articles, survey reports, academic literature, Chinese culture, and overview of China.\", \"th\": \"ประกอบด้วยรายงานข่าว บทความทางวิทยาศาสตร์ รายงานการสำรวจ วรรณกรรมเชิงวิชาการ วัฒนธรรมจีน และภาพรวมของจีน\", \"vi\": \"Bao gồm các bản tin, bài báo khoa học phổ biến, báo cáo điều tra, tài liệu học thuật, văn hóa Trung Quốc và tổng quan về Trung Quốc, v.v.\", \"zh\": \"包括新闻报道、科普文章、调查报告、学术文献、中华文化及中国概况等。\"}', 100, 47, 60, 2, 0, '2024-05-15 14:27:38', '2024-05-15 14:27:38');
INSERT INTO `mock_examination_segment` VALUES (28, 12, 'write', '写作', '{\"cn\": \"写作\", \"en\": \"Writing\", \"fr\": \"Expression écrite\", \"ja\": \"文章を書く\", \"ko\": \"Writing\", \"mn\": \"Бичих\", \"ru\": \"Письмо\", \"th\": \"การเขียน\", \"vi\": \"Kỹ năng viết\", \"zh\": \"写作\", \"ar\": \"الكتابة\", \"bg\": \"Писане \"}', '{\"cn\": \"描述与分析图表；根据所给话题发表及论证自己的看法。\", \"en\": \"Describe and analyse charts; express and defend opinions on given topics.\", \"fr\": \"Décrire et analyser des graphiques ; exprimer et défendre des opinions sur des sujets donnés.\", \"ja\": \"Describe and analyse charts; express and defend opinions on given topics.\", \"ko\": \"Describe and analyse charts; express and defend opinions on given topics.\", \"mn\": \"Зураг хүснэгтийг тайлбарлах, анализ хийх; өгсөн сэдвийн дагуу өөрийн үзэл бодлыг илэрхийлэх, хамгаалах.\", \"ru\": \"Describe and analyse charts; express and defend opinions on given topics.\", \"th\": \"อธิบายแผนภูมิ และแสดงความคิดเห็นของตนเองตามหัวข้อที่กำหนด\", \"vi\": \"Mô tả và phân tích biểu đồ; phát biểu và chứng minh ý kiến ​​của bản thân dựa trên các chủ đề nhất định.\", \"zh\": \"描述与分析图表；根据所给话题发表及论证自己的看法。\"}', 100, 2, 55, 3, 0, '2024-05-15 14:31:50', '2024-05-15 14:31:50');
INSERT INTO `mock_examination_segment` VALUES (29, 12, 'translation', '翻译', '{\"cn\": \"翻译\", \"en\": \"Translating\", \"fr\": \"Translating\", \"ja\": \"翻訳\", \"ko\": \"Translating\", \"mn\": \"Орчуулах\", \"ru\": \"Translating\", \"th\": \"ความหมาย\", \"vi\": \"Phiên dịch\", \"zh\": \"翻译\", \"ar\": \"ترجمة\", \"bg\": \"Превод\"}', '{\"cn\": \"将说明文、记叙文、议论文等不同体裁的外文材料笔译或口译成中文。\", \"en\": \"Translate explanatory, narrative, and discursive texts from foreign languages to Chinese, in both written and oral forms.\", \"fr\": \"Traduire des textes explicatifs, narratifs et argumentatifs d\'une langue étrangère en chinois, à l\'écrit et à l\'oral.\", \"ja\": \"Translate explanatory, narrative, and discursive texts from foreign languages to Chinese, in both written and oral forms.\", \"ko\": \"Translate explanatory, narrative, and discursive texts from foreign languages to Chinese, in both written and oral forms.\", \"mn\": \"Тайлбар эх, тэмдэглэл эх, мэтгэлцээн эх зэрэг олон төрлийн гадаад хэл дээрх материалд бичгийн болон аман хэлбэрээр хятад хэлэнд хөрвүүлэх.\", \"ru\": \"Translate explanatory, narrative, and discursive texts from foreign languages to Chinese, in both written and oral forms.\", \"th\": \"แปลหรือตีความสื่อภาษาต่างประเทศประเภทต่างๆ เช่น เรียงความเชิงอธิบาย เรียงความเชิงบรรยาย และเรียงความเชิงโต้แย้งเป็นภาษาจีน\", \"vi\": \"Dịch hoặc phiên dịch các tài liệu tiếng nước ngoài thuộc nhiều thể loại khác nhau như văn bản thuyết minh, băn bản tường thuật, luận văn sang tiếng Trung.\", \"zh\": \"将说明文、记叙文、议论文等不同体裁的外文材料笔译或口译成中文。\"}', 100, 4, 41, 4, 0, '2024-05-15 14:33:24', '2024-05-15 14:33:24');
INSERT INTO `mock_examination_segment` VALUES (30, 12, 'speaking', '口语', '{\"cn\": \"口语\", \"en\": \"Speaking\", \"fr\": \"Oral\", \"ja\": \"話し言葉\", \"ko\": \"Speaking\", \"mn\": \"Яриа\", \"ru\": \"Speaking\", \"th\": \"การพูด\", \"vi\": \"Khẩu ngữ\", \"zh\": \"口语\", \"ar\": \"التحدث\", \"bg\": \"Разговорен\"}', '{\"cn\": \"就应用文、记叙文、议论文等材料转述或发表自己的观点。\", \"en\": \"Paraphrase or express your own opinions on practical documentation, narrative texts, discursive essays etc.\", \"fr\": \"Paraphraser ou exprimer vos propres opinions sur des documents pratiques, des textes narratifs, des essais argumentatifs, etc.\", \"ja\": \"Paraphrase or express your own opinions on practical documentation, narrative texts, discursive essays etc.\", \"ko\": \"Paraphrase or express your own opinions on practical documentation, narrative texts, discursive essays etc.\", \"mn\": \"Хэрэглээний эх, тэмдэглэл эх, мэтгэлцээ эх зэрэг материалыг хувиргах эсвэл өөрийн үзэл бодлыг илэрхийлэх.\", \"ru\": \"Paraphrase or express your own opinions on practical documentation, narrative texts, discursive essays etc.\", \"th\": \"ถอดความหมายของบทความ หรือแสดงความคิดเห็นของตนเองจากบทความ\", \"vi\": \"Trình bày hoặc bày tỏ ý kiến ​​của riêng mình về các bài văn ứng dụng, văn tường thuật luận văn và các tài liệu khác.\", \"zh\": \"就应用文、记叙文、议论文等材料转述或发表自己的观点。\"}', 100, 5, 44, 5, 0, '2024-05-15 14:39:30', '2024-05-15 14:39:30');
INSERT INTO `mock_examination_segment` VALUES (31, 8, 'speaking', '口语', '{\"cn\": \"口语\", \"en\": \"Speaking\", \"fr\": \"Oral\", \"ja\": \"話し言葉\", \"ko\": \"Speaking\", \"mn\": \"Яриа\", \"ru\": \"Speaking\", \"th\": \"การพูด\", \"vi\": \"Khẩu ngữ\", \"zh\": \"口语\", \"ar\": \"التحدث\", \"bg\": \"Разговорен\"}', '{\"bg\": \"HSK Устен изпит (начално ниво) оценява устната изразност на кандидатите. То съответства на Международния стандарт за китайски език – ниво 1–2 и CEF – ниво A. Кандидатите, издържали този изпит, могат да разбират и устно да изразяват познати ежедневни теми, задоволявайки основни комуникативни нужди.\", \"cn\": \"HSK 口试（初级）考查考生的汉语口头表达能力，它对应于《国际汉语能力标准》一、二级，《欧洲语言共同参考框架（CEF）》A 级。通过 HSK 口试（初级）的考生可以听懂并用汉语口头表达较为熟悉的日常话题，满足基本交际需求。\", \"en\": \"The HSK Speaking Test (Primary Level) assesses the candidiates\' ability to express themselves in oral Chinese. It is the counterpart of the Level I and Level II of the Chinese Language Proficiency Scales for Speakers of Other Languages and the A Level of the Common European Framework of Reference (CEF). Candidiates who are able to pass the HSK Speaking Test (Primary Level) can understand and use familiar everyday expressions and meet specific needs for communication.\", \"ja\": \"HSKK口試（初級）は、受験生の中国語の口頭での表現能力を判定する試験で、『国際中国語能力基準（国际汉语能力标准）』1-2級および『ヨーロッパ言語共通参照枠（CEFR）』Aに準拠しています。HSKK口試（初級）の合格者は、身近な日常の話題についての口頭表現を聞いて理解したり、使ったりすることができ、基本的なコミュニケーションの需要を満たすことができます。\", \"ru\": \"HSK Устный экзамен (Начальный уровень) проверяет устные коммуникативные навыки на китайском языке. Соответствует уровням 1 и 2 Международного стандарта и уровню A CEFR. Сдавшие экзамен могут понимать и обсуждать знакомые повседневные темы на китайском языке.\", \"zh\": \"HSK 口试（初级）考查考生的汉语口头表达能力，它对应于《国际汉语能力标准》一、二级，《欧洲语言共同参考框架（CEF）》A 级。通过 HSK 口试（初级）的考生可以听懂并用汉语口头表达较为熟悉的日常话题，满足基本交际需求。\"}', 100, 27, 20, 1, 0, '2024-05-17 10:44:08', '2024-05-17 10:44:08');
INSERT INTO `mock_examination_segment` VALUES (32, 13, 'speaking', '口语', '{\"cn\": \"口语\", \"en\": \"Speaking\", \"fr\": \"Oral\", \"ja\": \"話し言葉\", \"ko\": \"Speaking\", \"mn\": \"Яриа\", \"ru\": \"Speaking\", \"th\": \"การพูด\", \"vi\": \"Khẩu ngữ\", \"zh\": \"口语\", \"ar\": \"التحدث\", \"bg\": \"Разговорен\"}', '{\"bg\": \"HSK Устен изпит (средно ниво) оценява устната изразност на кандидатите. То съответства на Международния стандарт за китайски език – ниво 3–4 и CEF – ниво B. Кандидатите, издържали този изпит, могат да общуват на китайски сравнително свободно с носители на езика.\", \"cn\": \"HSK 口试（中级）考查考生的汉语口头表达能力，它对应于《国际汉语能力标准》三、四级，《欧洲语言共同参考框架（CEF）》B 级。通过 HSK 口试（中级）的考生可以听懂并用汉语较为流利地与汉语为母语者进行交流\", \"en\": \"The HSK Speaking Test (Intermediate Level) assesses candidiates\' ability to express themselves in oral Chinese. It is the counterpart of the Level III and Level IV of the Chinese Language Proficiency Scales for Speakers of Other Languages and the B Level of the Common European Framework of Reference (CEF). Candidiates who are able to pass the HSK Speaking Test (Intermediate Level) can understand intermediate Chinese and converse fluently with native Chinese speakers.\", \"ja\": \"HSKK口試（中級）は、受験生の中国語の口頭での表現能力を判定する試験で、『国際中国語能力基準（国际汉语能力标准）』3-4級および『ヨーロッパ言語共通参照枠（CEFR）』Bに準拠しています。HSKK口試（中級）の合格者は、母語話者との交流において、比較的流暢に中国語を聞いて理解したり、使ったりすることができます。\", \"ru\": \"HSK Устный экзамен (Средний уровень) проверяет способность к более беглому устному общению. Соответствует уровням 3 и 4 Международного стандарта и уровню B CEFR. Сдавшие экзамен могут достаточно свободно общаться с носителями языка.\", \"zh\": \"HSK 口试（中级）考查考生的汉语口头表达能力，它对应于《国际汉语能力标准》三、四级，《欧洲语言共同参考框架（CEF）》B 级。通过 HSK 口试（中级）的考生可以听懂并用汉语较为流利地与汉语为母语者进行交流。\"}', 100, 14, 23, 1, 0, '2024-05-17 10:45:28', '2024-05-17 10:45:28');
INSERT INTO `mock_examination_segment` VALUES (33, 14, 'speaking', '口语', '{\"cn\": \"口语\", \"en\": \"Speaking\", \"fr\": \"Oral\", \"ja\": \"話し言葉\", \"ko\": \"Speaking\", \"mn\": \"Яриа\", \"ru\": \"Speaking\", \"th\": \"การพูด\", \"vi\": \"Khẩu ngữ\", \"zh\": \"口语\", \"ar\": \"التحدث\", \"bg\": \"Разговорен\"}', '{\"bg\": \"HSK Устен изпит (високо ниво) оценява устната изразност на кандидатите. То съответства на Международния стандарт за китайски език – ниво 5 и CEF – ниво C. Кандидатите, издържали този изпит, могат свободно и гладко да изразяват своите мнения на китайски език.\", \"cn\": \"HSK 口试（高级）考查考生的汉语口头表达能力，它对应于《国际汉语能 力标准》五级、《欧洲语言共同参考框架（CEF）》C 级。通过 HSK 口试（高级） 的考生可以听懂并用汉语流利地表达自己的见解。\", \"en\": \"The HSK Speaking Test (Advanced Level) assesses the candidiates\' ability to express themselves orally in Chinese. It is the counterpart of the Level V of the Chinese Language Proficiency Scales for Speakers of Other Languages and the C Level of the Common European Framework of Reference (CEF). Candidiates who are able to pass the HSK Speaking Test (Advanced Level) can understand spoken Chinese and fluently express their ideas in Chinese.\", \"ja\": \"HSKK口試（高級）は、受験生の中国語の口頭での表現能力を判定する試験で、『国際中国語能力基準（国际汉语能力标准）』5級および『ヨーロッパ言語共通参照枠（CEFR）』Cに準拠しています。HSKK口試（高級）の合格者は、中国語をスムーズに聞いて理解したり、自身の意見を流暢に表現したりすることができます。\", \"ru\": \"HSK Устный экзамен (Продвинутый уровень) проверяет способность свободно выражать свои мнения на китайском языке. Соответствует 5 уровню Международного стандарта и уровню C CEFR. Сдавшие экзамен могут уверенно и грамотно выражать свои взгляды на китайском.\", \"zh\": \"HSK 口试（高级）考查考生的汉语口头表达能力，它对应于《国际汉语能 力标准》五级、《欧洲语言共同参考框架（CEF）》C 级。通过 HSK 口试（高级） 的考生可以听懂并用汉语流利地表达自己的见解。\"}', 100, 6, 25, 1, 0, '2024-05-17 10:45:40', '2024-05-17 10:45:40');
