INSERT INTO `mock_examination_segment` VALUES (50, 36, 'write', '书写', '{\"cn\": \"书写\", \"en\": \"Writing\", \"fr\": \"Expression écrite\", \"ja\": \"作文\", \"ko\": \"Writing\", \"mn\": \"Бичих\", \"ru\": \"Письмо\", \"th\": \"การเขียน\", \"vi\": \"Kỹ năng viết\", \"zh\": \"书写\", \"ar\": \"الكتابة\", \"bg\": \"Писане \"}', NULL, 100, 2, 45, 3, 0, '2021-05-24 09:37:29', '2021-05-24 09:37:29');
INSERT INTO `mock_examination_segment` VALUES (51, 37, 'listen', '听力', '{\"cn\": \"听力\", \"en\": \"Listening\", \"fr\": \"Compréhension orale\", \"ja\": \"聞き取り\", \"ko\": \"Listening\", \"mn\": \"Сонсгол\", \"ru\": \"Аудирование\", \"th\": \"การฟัง\", \"vi\": \"Kỹ năng nghe\", \"zh\": \"听力\", \"ar\": \"الاستماع\", \"bg\": \"Слушане\"}', '{\"cn\": \"包括新闻报道、商务谈判、辩论、采访、演讲/讲座、纪录片、会议发言等。\", \"en\": \"Includes news reports, business negotiations, debates, interviews, speeches/lectures, documentaries, conference speeches, etc.\", \"fr\": \"Inclut des reportages, des négociations commerciales, des débats, des interviews, des discours/conférences, des documentaires, des discours de conférence, etc.\", \"ja\": \"Includes news reports, business negotiations, debates, interviews, speeches/lectures, documentaries, conference speeches, etc.\", \"ko\": \"Includes news reports, business negotiations, debates, interviews, speeches/lectures, documentaries, conference speeches, etc.\", \"mn\": \"Мэдээ, бизнес хэлэлцээр, мэтгэлцээн, ярилцлага, илтгэл/лекц, баримтат кино, хурлын үг зэрэг багтана\", \"ru\": \"Includes news reports, business negotiations, debates, interviews, speeches/lectures, documentaries, conference speeches, etc.\", \"th\": \"ประกอบด้วยรายงานข่าว การเจรจาธุรกิจ การอภิปราย การสัมภาษณ์ การกล่าวสุนทรพจน์/การบรรยาย สารคดี การกล่าวสุนทรพจน์ในการประชุม ฯลฯ\", \"vi\": \"Bao gồm các bản tin, đàm phán kinh doanh, tranh luận, phỏng vấn, bài phát biểu/bài giảng, phim tài liệu, bài phát biểu hội nghị, v.v.\", \"zh\": \"包括新闻报道、商务谈判、辩论、采访、演讲/讲座、纪录片、会议发言等。\"}', 100, 40, 30, 1, 0, '2026-01-23 20:54:15', '2026-01-23 20:54:15');
INSERT INTO `mock_examination_segment` VALUES (52, 37, 'read', '阅读', '{\"cn\": \"阅读\", \"en\": \"Reading\", \"fr\": \"Lecture\", \"ja\": \"読解\", \"ko\": \"Reading\", \"mn\": \"Унших\", \"ru\": \"Чтение\", \"th\": \"การอ่าน\", \"vi\": \"Kỹ năng đọc hiểu\", \"zh\": \"阅读\", \"ar\": \"القراءة\", \"bg\": \"Четене \"}', '{\"cn\": \"包括新闻报道、科普文章、调查报告、学术文献、中华文化及中国概况等。\", \"en\": \"Involves news reports, scientific articles, survey reports, academic literature, Chinese culture, and overview of China.\", \"fr\": \"Implique des reportages, des articles scientifiques, des rapports d\'enquête, de la littérature académique, la culture chinoise et une vue d\'ensemble de la Chine.\", \"ja\": \"Involves news reports, scientific articles, survey reports, academic literature, Chinese culture, and overview of China.\", \"ko\": \"Involves news reports, scientific articles, survey reports, academic literature, Chinese culture, and overview of China.\", \"mn\": \"Мэдээ, танин мэдэхүйн нийтлэл, судалгааны тайлан, эрдэм шинжилгээний нийтлэл, хятад соёл, хятадын тойм зэрэг багтана\", \"ru\": \"Involves news reports, scientific articles, survey reports, academic literature, Chinese culture, and overview of China.\", \"th\": \"ประกอบด้วยรายงานข่าว บทความทางวิทยาศาสตร์ รายงานการสำรวจ วรรณกรรมเชิงวิชาการ วัฒนธรรมจีน และภาพรวมของจีน\", \"vi\": \"Bao gồm các bản tin, bài báo khoa học phổ biến, báo cáo điều tra, tài liệu học thuật, văn hóa Trung Quốc và tổng quan về Trung Quốc, v.v.\", \"zh\": \"包括新闻报道、科普文章、调查报告、学术文献、中华文化及中国概况等。\"}', 100, 47, 60, 2, 0, '2026-01-23 20:54:15', '2026-01-23 20:54:15');
INSERT INTO `mock_examination_segment` VALUES (53, 37, 'write', '写作', '{\"cn\": \"写作\", \"en\": \"Writing\", \"fr\": \"Expression écrite\", \"ja\": \"文章を書く\", \"ko\": \"Writing\", \"mn\": \"Бичих\", \"ru\": \"Письмо\", \"th\": \"การเขียน\", \"vi\": \"Kỹ năng viết\", \"zh\": \"写作\", \"ar\": \"الكتابة\", \"bg\": \"Писане \"}', '{\"cn\": \"描述与分析图表；根据所给话题发表及论证自己的看法。\", \"en\": \"Describe and analyse charts; express and defend opinions on given topics.\", \"fr\": \"Décrire et analyser des graphiques ; exprimer et défendre des opinions sur des sujets donnés.\", \"ja\": \"Describe and analyse charts; express and defend opinions on given topics.\", \"ko\": \"Describe and analyse charts; express and defend opinions on given topics.\", \"mn\": \"Зураг хүснэгтийг тайлбарлах, анализ хийх; өгсөн сэдвийн дагуу өөрийн үзэл бодлыг илэрхийлэх, хамгаалах.\", \"ru\": \"Describe and analyse charts; express and defend opinions on given topics.\", \"th\": \"อธิบายแผนภูมิ และแสดงความคิดเห็นของตนเองตามหัวข้อที่กำหนด\", \"vi\": \"Mô tả và phân tích biểu đồ; phát biểu và chứng minh ý kiến ​​của bản thân dựa trên các chủ đề nhất định.\", \"zh\": \"描述与分析图表；根据所给话题发表及论证自己的看法。\"}', 100, 2, 55, 3, 0, '2026-01-23 20:54:15', '2026-01-23 20:54:15');
INSERT INTO `mock_examination_segment` VALUES (54, 37, 'translation', '翻译', '{\"cn\": \"翻译\", \"en\": \"Translating\", \"fr\": \"Translating\", \"ja\": \"翻訳\", \"ko\": \"Translating\", \"mn\": \"Орчуулах\", \"ru\": \"Translating\", \"th\": \"ความหมาย\", \"vi\": \"Phiên dịch\", \"zh\": \"翻译\", \"ar\": \"ترجمة\", \"bg\": \"Превод\"}', '{\"cn\": \"将说明文、记叙文、议论文等不同体裁的外文材料笔译或口译成中文。\", \"en\": \"Translate explanatory, narrative, and discursive texts from foreign languages to Chinese, in both written and oral forms.\", \"fr\": \"Traduire des textes explicatifs, narratifs et argumentatifs d\'une langue étrangère en chinois, à l\'écrit et à l\'oral.\", \"ja\": \"Translate explanatory, narrative, and discursive texts from foreign languages to Chinese, in both written and oral forms.\", \"ko\": \"Translate explanatory, narrative, and discursive texts from foreign languages to Chinese, in both written and oral forms.\", \"mn\": \"Тайлбар эх, тэмдэглэл эх, мэтгэлцээн эх зэрэг олон төрлийн гадаад хэл дээрх материалд бичгийн болон аман хэлбэрээр хятад хэлэнд хөрвүүлэх.\", \"ru\": \"Translate explanatory, narrative, and discursive texts from foreign languages to Chinese, in both written and oral forms.\", \"th\": \"แปลหรือตีความสื่อภาษาต่างประเทศประเภทต่างๆ เช่น เรียงความเชิงอธิบาย เรียงความเชิงบรรยาย และเรียงความเชิงโต้แย้งเป็นภาษาจีน\", \"vi\": \"Dịch hoặc phiên dịch các tài liệu tiếng nước ngoài thuộc nhiều thể loại khác nhau như văn bản thuyết minh, băn bản tường thuật, luận văn sang tiếng Trung.\", \"zh\": \"将说明文、记叙文、议论文等不同体裁的外文材料笔译或口译成中文。\"}', 100, 4, 41, 4, 0, '2026-01-23 20:54:15', '2026-01-23 20:54:15');
INSERT INTO `mock_examination_segment` VALUES (55, 37, 'speaking', '口语', '{\"cn\": \"口语\", \"en\": \"Speaking\", \"fr\": \"Oral\", \"ja\": \"話し言葉\", \"ko\": \"Speaking\", \"mn\": \"Яриа\", \"ru\": \"Speaking\", \"th\": \"การพูด\", \"vi\": \"Khẩu ngữ\", \"zh\": \"口语\", \"ar\": \"التحدث\", \"bg\": \"Разговорен\"}', '{\"cn\": \"就应用文、记叙文、议论文等材料转述或发表自己的观点。\", \"en\": \"Paraphrase or express your own opinions on practical documentation, narrative texts, discursive essays etc.\", \"fr\": \"Paraphraser ou exprimer vos propres opinions sur des documents pratiques, des textes narratifs, des essais argumentatifs, etc.\", \"ja\": \"Paraphrase or express your own opinions on practical documentation, narrative texts, discursive essays etc.\", \"ko\": \"Paraphrase or express your own opinions on practical documentation, narrative texts, discursive essays etc.\", \"mn\": \"Хэрэглээний эх, тэмдэглэл эх, мэтгэлцээ эх зэрэг материалыг хувиргах эсвэл өөрийн үзэл бодлыг илэрхийлэх.\", \"ru\": \"Paraphrase or express your own opinions on practical documentation, narrative texts, discursive essays etc.\", \"th\": \"ถอดความหมายของบทความ หรือแสดงความคิดเห็นของตนเองจากบทความ\", \"vi\": \"Trình bày hoặc bày tỏ ý kiến ​​của riêng mình về các bài văn ứng dụng, văn tường thuật luận văn và các tài liệu khác.\", \"zh\": \"就应用文、记叙文、议论文等材料转述或发表自己的观点。\"}', 100, 5, 44, 5, 0, '2026-01-23 20:54:15', '2026-01-23 20:54:15');
INSERT INTO `mock_examination_segment` VALUES (56, 43, 'speaking', '口语', '{\"cn\": \"口语\", \"en\": \"Speaking\", \"fr\": \"Oral\", \"ja\": \"話し言葉\", \"ko\": \"Speaking\", \"mn\": \"Яриа\", \"ru\": \"Speaking\", \"th\": \"การพูด\", \"vi\": \"Khẩu ngữ\", \"zh\": \"口语\", \"ar\": \"التحدث\", \"bg\": \"Разговорен\"}', NULL, 100, 15, 15, 1, 0, '2026-01-05 19:41:55', '2026-01-05 19:41:55');
INSERT INTO `mock_examination_segment` VALUES (57, 44, 'speaking', '口语', '{\"cn\": \"口语\", \"en\": \"Speaking\", \"fr\": \"Oral\", \"ja\": \"話し言葉\", \"ko\": \"Speaking\", \"mn\": \"Яриа\", \"ru\": \"Speaking\", \"th\": \"การพูด\", \"vi\": \"Khẩu ngữ\", \"zh\": \"口语\", \"ar\": \"التحدث\", \"bg\": \"Разговорен\"}', NULL, 100, 5, 20, 1, 0, '2026-01-05 19:41:55', '2026-01-05 19:41:55');
INSERT INTO `mock_examination_segment` VALUES (58, 45, 'speaking', '口语', '{\"cn\": \"口语\", \"en\": \"Speaking\", \"fr\": \"Oral\", \"ja\": \"話し言葉\", \"ko\": \"Speaking\", \"mn\": \"Яриа\", \"ru\": \"Speaking\", \"th\": \"การพูด\", \"vi\": \"Khẩu ngữ\", \"zh\": \"口语\", \"ar\": \"التحدث\", \"bg\": \"Разговорен\"}', NULL, 100, 5, 23, 1, 0, '2026-01-05 19:41:55', '2026-01-05 19:41:55');
INSERT INTO `mock_examination_segment` VALUES (59, 46, 'speaking', '口语', '{\"cn\": \"口语\", \"en\": \"Speaking\", \"fr\": \"Oral\", \"ja\": \"話し言葉\", \"ko\": \"Speaking\", \"mn\": \"Яриа\", \"ru\": \"Speaking\", \"th\": \"การพูด\", \"vi\": \"Khẩu ngữ\", \"zh\": \"口语\", \"ar\": \"التحدث\", \"bg\": \"Разговорен\"}', NULL, 100, 5, 23, 1, 0, '2026-01-05 19:41:55', '2026-01-05 19:41:55');
INSERT INTO `mock_levels` VALUES (1, 1, 1, 'HSK', 'HSK1', '{\"ar\": \"1\", \"bg\": \"1\", \"cn\": \"1\", \"en\": \"1\", \"fr\": \"1\", \"ja\": \"1\", \"ko\": \"1\", \"mn\": \"1\", \"ru\": \"1\", \"th\": \"1\", \"vi\": \"1\", \"zh\": \"1\"}', '{\"ar\": \"المستوى 1\", \"bg\": \"Ниво 1\", \"cn\": \"一级\", \"en\": \"Level 1\", \"fr\": \"Niveau 1\", \"ja\": \"1級\", \"ko\": \"Level 1\", \"mn\": \"1-р түвшин\", \"ru\": \"Уровень 1\", \"th\": \"ระดับ 1\", \"vi\": \"Cấp độ 1\", \"zh\": \"一级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=826485', '{\"zh\":\"通过 HSK(一级)的考生可以理解并使用一些非常简单的汉语词语和句子，满足具体的交际需求，具备进一步学习汉语的能力。\",\"cn\":\"通过 HSK(一级)的考生可以理解并使用一些非常简单的汉语词语和句子，满足具体的交际需求，具备进一步学习汉语的能力。\",\"en\":\"Candidates who pass the HSK Level 1 exam can understand and use some very simple Chinese words and sentences to meet specific communication needs, and are able to take the next step in their Chinese studies.\"}', '本课程适合未系统学习过汉语的零起点学习者以及准备参加HSK1级考试的汉语学习者。\r\n每课视频围绕一个主题，分为若干场景，让学生在情境中学习生词、课文和语法。通过系统、形象及生动的练习，提高学生的汉语运用能力。', 'This course is suitable for beginners who have not studied Chinese systematically and Chinese learners who are preparing to take the HSK1 test.\r\nEach lesson focuses on one theme which is divided into several scenes, allowing students to learn new words, texts and grammar in the context. Students\' ability to use Chinese will be improved through systematic, visual and vivid exercises.\r\n', 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 0, '2020-11-05 19:37:20', '2020-11-05 19:37:20', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (2, 2, 1, 'HSK', 'HSK2', '{\"ar\": \"2\", \"bg\": \"2\", \"cn\": \"2\", \"en\": \"2\", \"fr\": \"2\", \"ja\": \"2\", \"ko\": \"2\", \"mn\": \"2\", \"ru\": \"2\", \"th\": \"2\", \"vi\": \"2\", \"zh\": \"2\"}', '{\"ar\": \"المستوى 2\", \"bg\": \"Ниво 2\", \"cn\": \"二级\", \"en\": \"Level 2\", \"fr\": \"Niveau 2\", \"ja\": \"2級\", \"ko\": \"Level 2\", \"mn\": \"2-р түвшин\", \"ru\": \"Уровень 2\", \"th\": \"ระดับ 2\", \"vi\": \"Cấp độ 2\", \"zh\": \"二级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=826486', '{\"zh\":\"通过 HSK(二级)的考生可以用汉语就熟悉的日常话题进行简单而直接的交流，达到初级汉语优等水平。 \",\"cn\":\"通过 HSK(二级)的考生可以用汉语就熟悉的日常话题进行简单而直接的交流，达到初级汉语优等水平。 \",\"en\":\"Candidates who pass the HSK Level 2 exam can communicate simply and directly in Chinese on familiar everyday topics, having reached an advanced level in elementary Chinese.\"}', '本课程适合已经掌握150个左右汉语词汇的学习者以及准备参加HSK2级考试的汉语学习者。\r\n每课视频围绕一个任务主题分四个场景展开，让学生在场景中学习生词、课文和语法，并通过练习训练学生的听说能力和语言交际能力，让学习者学得轻松而高效。', 'This course is suitable for learners who have mastered about 150 Chinese vocabulary and Chinese learners who are preparing to take the HSK2 test.\r\nEach lesson is divided into four scenes around a task theme, allowing students to learn new words, texts and grammar in the scenes, and train students\' listening and speaking skills and language communication skills through practice, so that learners can learn Chinese in an easy and efficient way.\r\n', 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 0, '2020-11-05 19:37:20', '2020-11-05 19:37:20', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (3, 3, 1, 'HSK', 'HSK3', '{\"ar\": \"3\", \"bg\": \"3\", \"cn\": \"3\", \"en\": \"3\", \"fr\": \"3\", \"ja\": \"3\", \"ko\": \"3\", \"mn\": \"3\", \"ru\": \"3\", \"th\": \"3\", \"vi\": \"3\", \"zh\": \"3\"}', '{\"ar\": \"المستوى 3\", \"bg\": \"Ниво 3\", \"cn\": \"三级\", \"en\": \"Level 3\", \"fr\": \"Niveau 3\", \"ja\": \"3級\", \"ko\": \"Level 3\", \"mn\": \"3-р түвшин\", \"ru\": \"Уровень 3\", \"th\": \"ระดับ 3\", \"vi\": \"Cấp độ 3\", \"zh\": \"三级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828635', '{\"zh\":\"通过 HSK(三级)的考生可以用汉语完成生活、学习、工作等方面的基本交际任务，在中国旅游时，可应对遇到的大部分交际任务。\",\"cn\":\"通过 HSK(三级)的考生可以用汉语完成生活、学习、工作等方面的基本交际任务，在中国旅游时，可应对遇到的大部分交际任务。\",\"en\":\"Candidates who pass the HSK Level 3 exam can use Chinese to complete basic communication tasks in everyday life and in their studies, and can deal with most of the communication tasks encountered when travelling in China.\"}', '本课程适合已经掌握300个左右汉语词汇的学习者以及准备参加HSK3级考试的汉语学习者。\r\n每课视频包含四个不同场景，通过对话或者短文形式，在不同场景下复现该课的生词和语法，并通过多样的练习加以强化，以培养学习者的日常运用以及成段表达的能力。', 'This course is suitable for learners who have mastered about 300 Chinese vocabulary and Chinese learners who are preparing to take the HSK3 test.\r\nEach lesson contains four different scenes. Through dialogue or short essays, the new words and grammar of the lesson are reproduced in different scenes. Learners\' memory of those new words and grammar will also be strengthened through various exercises. This particular way can cultivate learners\' daily use of Chinese and their ability to express in paragraphs.\r\n', 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 0, '2020-11-05 19:37:20', '2020-11-05 19:37:20', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (4, 4, 1, 'HSK', 'HSK4', '{\"ar\": \"4\", \"bg\": \"4\", \"cn\": \"4\", \"en\": \"4\", \"fr\": \"4\", \"ja\": \"4\", \"ko\": \"4\", \"mn\": \"4\", \"ru\": \"4\", \"th\": \"4\", \"vi\": \"4\", \"zh\": \"4\"}', '{\"ar\": \"المستوى 4\", \"bg\": \"Ниво 4\", \"cn\": \"四级\", \"en\": \"Level 4\", \"fr\": \"Niveau 4\", \"ja\": \"4級\", \"ko\": \"Level 4\", \"mn\": \"4-р түвшин\", \"ru\": \"Уровень 4\", \"th\": \"ระดับ 4\", \"vi\": \"Cấp độ 4\", \"zh\": \"四级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828636', '{\"zh\":\"通过 HSK(四级)的考生可以用汉语就较广泛领域的话题进行谈论，比较流利地与汉语为母语者进行交流。 \",\"cn\":\"通过 HSK(四级)的考生可以用汉语就较广泛领域的话题进行谈论，比较流利地与汉语为母语者进行交流。 \",\"en\":\"Candidates who pass the HSK Level 4 exam can talk in Chinese on a wider range of topics and communicate relatively fluently with native speakers of Chinese.\"}', '描述文本未提供', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 1, '2021-05-19 15:15:16', '2021-05-19 15:15:16', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (5, 5, 1, 'HSK', 'HSK5', '{\"ar\": \"5\", \"bg\": \"5\", \"cn\": \"5\", \"en\": \"5\", \"fr\": \"5\", \"ja\": \"5\", \"ko\": \"5\", \"mn\": \"5\", \"ru\": \"5\", \"th\": \"5\", \"vi\": \"5\", \"zh\": \"5\"}', '{\"ar\": \"المستوى 5\", \"bg\": \"Ниво 5\", \"cn\": \"五级\", \"en\": \"Level 5\", \"fr\": \"Niveau 5\", \"ja\": \"5級\", \"ko\": \"Level 5\", \"mn\": \"5-р түвшин\", \"ru\": \"Уровень 5\", \"th\": \"ระดับ 5\", \"vi\": \"Cấp độ 5\", \"zh\": \"五级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828637', '{\"zh\":\"通过 HSK(五级)的考生可以阅读汉语报刊杂志，欣赏汉语影视节目，用汉语进行较为完整的演讲。\",\"cn\":\"通过 HSK(五级)的考生可以阅读汉语报刊杂志，欣赏汉语影视节目，用汉语进行较为完整的演讲。\",\"en\":\"Candidates who pass the HSK Level 5 exam can read Chinese newspapers and magazines, enjoy Chinese films and television programs, and give more complete speeches in Chinese.\"}', '描述文本未提供', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 1, '2021-05-19 15:15:33', '2021-05-19 15:15:33', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (6, 6, 1, 'HSK', 'HSK6', '{\"ar\": \"6\", \"bg\": \"6\", \"cn\": \"6\", \"en\": \"6\", \"fr\": \"6\", \"ja\": \"5\", \"ko\": \"6\", \"mn\": \"6\", \"ru\": \"6\", \"th\": \"6\", \"vi\": \"6\", \"zh\": \"6\"}', '{\"ar\": \"المستوى 6\", \"bg\": \"Ниво 6\", \"cn\": \"六级\", \"en\": \"Level 6\", \"fr\": \"Niveau 6\", \"ja\": \"6級\", \"ko\": \"Level 6\", \"mn\": \"6-р түвшин\", \"ru\": \"Уровень 6\", \"th\": \"ระดับ 6\", \"vi\": \"Cấp độ 6\", \"zh\": \"六级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828638', '{\"zh\":\"通过 HSK(六级)的考生可以轻松地理解听到或读到的汉语信息，以口头或书面的形式用汉语流利地表达自己的见解。\",\"cn\":\"通过 HSK(六级)的考生可以轻松地理解听到或读到的汉语信息，以口头或书面的形式用汉语流利地表达自己的见解。\",\"en\":\"Candidates who pass the HSK Level 6 exam can easily understand information they hear or read in Chinese, and can express their opinions in Chinese fluently either orally or in writing.\"}', '描述文本未提供', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 1, '2021-05-19 15:15:39', '2021-05-19 15:15:39', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (7, 1, 3, 'YCT', 'YCT1', '{\"ar\": \"1\", \"bg\": \"1\", \"cn\": \"1\", \"en\": \"1\", \"fr\": \"1\", \"ja\": \"1\", \"ko\": \"1\", \"mn\": \"1\", \"ru\": \"1\", \"th\": \"1\", \"vi\": \"1\", \"zh\": \"1\"}', '{\"ar\": \"المستوى 1\", \"bg\": \"Ниво 1\", \"cn\": \"一级\", \"en\": \"Level 1\", \"fr\": \"Niveau 1\", \"ja\": \"1級\", \"ko\": \"Level 1\", \"mn\": \"1-р түвшин\", \"ru\": \"Уровень 1\", \"th\": \"ระดับ 1\", \"vi\": \"Cấp độ 1\", \"zh\": \"一级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828753', '{\"zh\":\"通过 YCT（一级）的考生可以理解并使用最常用的汉语词语和句子，具备进一步学习汉语的能力。\",\"cn\":\"通过 YCT（一级）的考生可以理解并使用最常用的汉语词语和句子，具备进一步学习汉语的能力。\",\"en\":\"Candidates who pass the YCT Level 1 exam can understand and use the most commonly used Chinese words and sentences, and are able to take the next step in their Chinese studies.\"}', 'YCT1', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 0, '2021-11-18 15:35:47', '2021-11-18 15:35:47', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (8, 1, 2, 'HSKK', 'HSKK1', '{\"ar\": \"المستوى الابتدائي\", \"bg\": \"начален\", \"cn\": \"初级\", \"en\": \"Primary\", \"fr\": \"Débutant\", \"ja\": \"初級\", \"ko\": \"Primary\", \"mn\": \"Анхан шат\", \"ru\": \"начальный уровень\", \"th\": \"ระดับต้น\", \"vi\": \"Sơ cấp\", \"zh\": \"初级\"}', '{\"ar\": \"المستوى الابتدائي\", \"bg\": \"начален\", \"cn\": \"初级\", \"en\": \"Primary\", \"fr\": \"Débutant\", \"ja\": \"初級\", \"ko\": \"Primary\", \"mn\": \"Анхан шат\", \"ru\": \"начальный уровень\", \"th\": \"ระดับต้น\", \"vi\": \"Sơ cấp\", \"zh\": \"初级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=826485', '{\"zh\":\"HSK 口试（初级）考查考生的汉语口头表达能力，它对应于《国际汉语能力标准》一、二级，《欧洲语言共同参考框架（CEF）》A 级。通过 HSK 口试（初级）的考生可以听懂并用汉语口头表达较为熟悉的日常话题，满足基本交际需求。\",\"cn\":\"HSK 口试（初级）考查考生的汉语口头表达能力，它对应于《国际汉语能力标准》一、二级，《欧洲语言共同参考框架（CEF）》A 级。通过 HSK 口试（初级）的考生可以听懂并用汉语口头表达较为熟悉的日常话题，满足基本交际需求。\",\"en\":\"The HSK Speaking Test (Primary Level) assesses the candidiates\' ability to express themselves in oral Chinese. It is the counterpart of the Level I and Level II of the Chinese Language Proficiency Scales for Speakers of Other Languages and the A Level of the Common European Framework of Reference (CEF). Candidiates who are able to pass the HSK Speaking Test (Primary Level) can understand and use familiar everyday expressions and meet specific needs for communication.\",\"ja\":\"HSKK口試（初級）は、受験生の中国語の口頭での表現能力を判定する試験で、『国際中国語能力基準（国际汉语能力标准）』1-2級および『ヨーロッパ言語共通参照枠（CEFR）』Aに準拠しています。HSKK口試（初級）の合格者は、身近な日常の話題についての口頭表現を聞いて理解したり、使ったりすることができ、基本的なコミュニケーションの需要を満たすことができます。\"}', 'HSKK初级', 'HSKK Primary', 'https://staging-public.hskmock.com/hsk-examination/hskk1/hskk1_2_3.mp3', 0, 1, '2021-11-08 17:22:42', '2025-03-27 17:22:42', 1, 1, 20, 1);
INSERT INTO `mock_levels` VALUES (9, 2, 3, 'YCT', 'YCT2', '{\"ar\": \"2\", \"bg\": \"2\", \"cn\": \"2\", \"en\": \"2\", \"fr\": \"2\", \"ja\": \"2\", \"ko\": \"2\", \"mn\": \"2\", \"ru\": \"2\", \"th\": \"2\", \"vi\": \"2\", \"zh\": \"2\"}', '{\"ar\": \"المستوى 2\", \"bg\": \"Ниво 2\", \"cn\": \"二级\", \"en\": \"Level 2\", \"fr\": \"Niveau 2\", \"ja\": \"2級\", \"ko\": \"Level 2\", \"mn\": \"2-р түвшин\", \"ru\": \"Уровень 2\", \"th\": \"ระดับ 2\", \"vi\": \"Cấp độ 2\", \"zh\": \"二级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828754', '{\"zh\":\"通过 YCT（二级）的考生可以理解并使用一些非常简单的汉语词语和句子，满足具体的交际需求。\",\"cn\":\"通过 YCT（二级）的考生可以理解并使用一些非常简单的汉语词语和句子，满足具体的交际需求。\",\"en\":\"Candidates who pass the YCT Level 2 exam can understand and use some very simple Chinese words and sentences to meet specific communication needs.\"}', 'YCT2', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 0, '2022-05-30 14:31:38', '2022-05-30 14:31:38', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (10, 3, 3, 'YCT', 'YCT3', '{\"ar\": \"3\", \"bg\": \"3\", \"cn\": \"3\", \"en\": \"3\", \"fr\": \"3\", \"ja\": \"3\", \"ko\": \"3\", \"mn\": \"3\", \"ru\": \"3\", \"th\": \"3\", \"vi\": \"3\", \"zh\": \"3\"}', '{\"ar\": \"المستوى 3\", \"bg\": \"Ниво 3\", \"cn\": \"三级\", \"en\": \"Level 3\", \"fr\": \"Niveau 3\", \"ja\": \"3級\", \"ko\": \"Level 3\", \"mn\": \"3-р түвшин\", \"ru\": \"Уровень 3\", \"th\": \"ระดับ 3\", \"vi\": \"Cấp độ 3\", \"zh\": \"三级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828755', '{\"zh\":\"通过 YCT（三级）的考生可以用汉语就熟悉的日常话题进行简单而直接的交流，达到初级汉语优等水平。\",\"cn\":\"通过 YCT（三级）的考生可以用汉语就熟悉的日常话题进行简单而直接的交流，达到初级汉语优等水平。\",\"en\":\"Candidates who pass the YCT Level 3 exam can communicate simply and directly in Chinese on familiar everyday topics, having reached an advanced level in elementary Chinese.\"}', 'YCT3', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 0, '2022-05-30 14:31:38', '2022-05-30 14:31:38', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (11, 4, 3, 'YCT', 'YCT4', '{\"ar\": \"4\", \"bg\": \"4\", \"cn\": \"4\", \"en\": \"4\", \"fr\": \"4\", \"ja\": \"4\", \"ko\": \"4\", \"mn\": \"4\", \"ru\": \"4\", \"th\": \"4\", \"vi\": \"4\", \"zh\": \"4\"}', '{\"ar\": \"المستوى 4\", \"bg\": \"Ниво 4\", \"cn\": \"四级\", \"en\": \"Level 4\", \"fr\": \"Niveau 4\", \"ja\": \"4級\", \"ko\": \"Level 4\", \"mn\": \"4-р түвшин\", \"ru\": \"Уровень 4\", \"th\": \"ระดับ 4\", \"vi\": \"Cấp độ 4\", \"zh\": \"四级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828756', '{\"zh\":\"通过 YCT（四级）的考生可以运用汉语完成生活、学习中的基本交际任务，在中国旅游时，可应对遇到的大部分交际任务。\",\"cn\":\"通过 YCT（四级）的考生可以运用汉语完成生活、学习中的基本交际任务，在中国旅游时，可应对遇到的大部分交际任务。\",\"en\":\"Candidates who pass the YCT Level 4 exam can use Chinese to complete basic communication tasks in everyday life and in their studies, and can deal with most of the communication tasks encountered when travelling in China.\"}', 'YCT4', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 0, '2022-05-30 14:31:38', '2022-05-30 14:31:38', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (12, 7, 1, 'HSK', 'New HSK7-9', '{\"ar\": \"7-9\", \"bg\": \"7-9\", \"cn\": \"7-9\", \"en\": \"7-9\", \"fr\": \"7-9\", \"ja\": \"7-9\", \"ko\": \"7-9\", \"mn\": \"7-9\", \"ru\": \"7-9\", \"th\": \"7-9\", \"vi\": \"7-9\", \"zh\": \"7-9\"}', '{\"ar\": \"المستوى 7-9\", \"bg\": \"Ниво 7-9\", \"cn\": \"七-九级\", \"en\": \"Level 7-9\", \"fr\": \"Niveau 7-9\", \"ja\": \"7-9級\", \"ko\": \"Level 7-9\", \"mn\": \"7-9-р түвшин\", \"ru\": \"Уровень 7-9\", \"th\": \"ระดับ 7-9\", \"vi\": \"Cấp độ 7-9\", \"zh\": \"七-九级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828638', '{\"zh\":\"通过HSK（七级）的考生具备良好的听、说、读、写能力和初步的专业翻译能力。能够就较为广泛和较高层次的话题进行基本、规范、流利、得体的社会交际。通过HSK（八级）的考生具备良好的听、说、读、写能力和基本的专业翻译能力。能够就各类高层次或专业话题进行较为规范、流利、得体的社会交际。通过HSK（九级）的考生具备良好的听、说、读、写能力和专业翻译能力。能够综合运用各种技能，在各种情境下，就各类话题进行规范、流利、得体的社会交际。\",\"cn\":\"通过HSK（七级）的考生具备良好的听、说、读、写能力和初步的专业翻译能力。能够就较为广泛和较高层次的话题进行基本、规范、流利、得体的社会交际。通过HSK（八级）的考生具备良好的听、说、读、写能力和基本的专业翻译能力。能够就各类高层次或专业话题进行较为规范、流利、得体的社会交际。通过HSK（九级）的考生具备良好的听、说、读、写能力和专业翻译能力。能够综合运用各种技能，在各种情境下，就各类话题进行规范、流利、得体的社会交际。\",\"en\":\"Candidates who pass HSK Level 7 possess good listening, speaking, reading, and writing abilities, as well as preliminary professional translation skills. They are capable of engaging in basic, standardized, fluent, and appropriate social interactions on relatively broad and high-level topics.Candidates who pass HSK Level 8 possess good listening, speaking, reading, and writing abilities, as well as basic professional translation skills. They can engage in relatively standardized, fluent, and appropriate social interactions on various high-level or professional topics.Candidates who pass HSK Level 9 possess good listening, speaking, reading, and writing abilities, as well as professional translation skills. They are capable of integrating various skills and engaging in standardized, fluent, and appropriate social interactions on various topics in different contexts.\"}', 'hsk7-9', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 1, '2021-05-19 15:15:39', '2021-05-19 15:15:39', 1, 1, NULL, 2);
INSERT INTO `mock_levels` VALUES (13, 2, 2, 'HSKK', 'HSKK2', '{\"ar\": \"المستوى المتوسط\", \"bg\": \"среден\", \"cn\": \"中级\", \"en\": \"Intermediate\", \"fr\": \"Intermédiaire\", \"ja\": \"中級\", \"ko\": \"Intermediate\", \"mn\": \"Дунд шат\", \"ru\": \"средний уровень\", \"th\": \"ระดับกลาง\", \"vi\": \"Trung cấp\", \"zh\": \"中级\"}', '{\"ar\": \"المستوى المتوسط\", \"bg\": \"среден\", \"cn\": \"中级\", \"en\": \"Intermediate\", \"fr\": \"Intermédiaire\", \"ja\": \"中級\", \"ko\": \"Intermediate\", \"mn\": \"Дунд шат\", \"ru\": \"средний уровень\", \"th\": \"ระดับกลาง\", \"vi\": \"Trung cấp\", \"zh\": \"中级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=826485', '{\"zh\":\"HSK 口试（中级）考查考生的汉语口头表达能力，它对应于《国际汉语能力标准》三、四级，《欧洲语言共同参考框架（CEF）》B 级。通过 HSK 口试（中级）的考生可以听懂并用汉语较为流利地与汉语为母语者进行交流。\",\"cn\":\"HSK 口试（中级）考查考生的汉语口头表达能力，它对应于《国际汉语能力标准》三、四级，《欧洲语言共同参考框架（CEF）》B 级。通过 HSK 口试（中级）的考生可以听懂并用汉语较为流利地与汉语为母语者进行交流\",\"en\":\"The HSK Speaking Test (Intermediate Level) assesses candidiates\' ability to express themselves in oral Chinese. It is the counterpart of the Level III and Level IV of the Chinese Language Proficiency Scales for Speakers of Other Languages and the B Level of the Common European Framework of Reference (CEF). Candidiates who are able to pass the HSK Speaking Test (Intermediate Level) can understand intermediate Chinese and converse fluently with native Chinese speakers.\" ,\"ja\":\"HSKK口試（中級）は、受験生の中国語の口頭での表現能力を判定する試験で、『国際中国語能力基準（国际汉语能力标准）』3-4級および『ヨーロッパ言語共通参照枠（CEFR）』Bに準拠しています。HSKK口試（中級）の合格者は、母語話者との交流において、比較的流暢に中国語を聞いて理解したり、使ったりすることができます。\"}', 'HSKK中级', 'HSKK Intermediate', 'https://staging-public.hskmock.com/hsk-examination/hskk2/hskk1_2_3.mp3', 0, 1, '2021-11-08 17:22:42', '2025-03-27 17:22:42', 1, 1, 23, 1);
INSERT INTO `mock_levels` VALUES (14, 3, 2, 'HSKK', 'HSKK3', '{\"ar\": \"المستوى المتقدم\", \"bg\": \"напреднал\", \"cn\": \"高级\", \"en\": \"Advanced\", \"fr\": \"Avancé\", \"ja\": \"高級\", \"ko\": \"Advanced\", \"mn\": \"Өндөр шат\", \"ru\": \"продвинутый уровень\", \"th\": \"ระดับสูง\", \"vi\": \"Cao cấp\", \"zh\": \"高级\"}', '{\"ar\": \"المستوى المتقدم\", \"bg\": \"напреднал\", \"cn\": \"高级\", \"en\": \"Advanced\", \"fr\": \"Avancé\", \"ja\": \"高級\", \"ko\": \"Advanced\", \"mn\": \"Өндөр шат\", \"ru\": \"продвинутый уровень\", \"th\": \"ระดับสูง\", \"vi\": \"Cao cấp\", \"zh\": \"高级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=826485', '{\"zh\":\"HSK 口试（高级）考查考生的汉语口头表达能力，它对应于《国际汉语能 力标准》五级、《欧洲语言共同参考框架（CEF）》C 级。通过 HSK 口试（高级） 的考生可以听懂并用汉语流利地表达自己的见解。\",\"cn\":\"HSK 口试（高级）考查考生的汉语口头表达能力，它对应于《国际汉语能 力标准》五级、《欧洲语言共同参考框架（CEF）》C 级。通过 HSK 口试（高级） 的考生可以听懂并用汉语流利地表达自己的见解。\",\"en\":\"The HSK Speaking Test (Advanced Level) assesses the candidiates\' ability to express themselves orally in Chinese. It is the counterpart of the Level V of the Chinese Language Proficiency Scales for Speakers of Other Languages and the C Level of the Common European Framework of Reference (CEF). Candidiates who are able to pass the HSK Speaking Test (Advanced Level) can understand spoken Chinese and fluently express their ideas in Chinese.\",\"ja\":\"HSKK口試（高級）は、受験生の中国語の口頭での表現能力を判定する試験で、『国際中国語能力基準（国际汉语能力标准）』5級および『ヨーロッパ言語共通参照枠（CEFR）』Cに準拠しています。HSKK口試（高級）の合格者は、中国語をスムーズに聞いて理解したり、自身の意見を流暢に表現したりすることができます。\"}', 'HSKK高级', 'HSKK Advanced', 'https://staging-public.hskmock.com/hsk-examination/hskk3/hskk1_2_3.mp3', 0, 1, '2021-11-08 17:22:42', '2025-03-27 17:22:42', 1, 1, 25, 1);
INSERT INTO `mock_levels` VALUES (31, 1, 4, 'New-HSK', 'New HSK1', '{\"ar\": \"1\", \"bg\": \"1\", \"cn\": \"1\", \"en\": \"1\", \"fr\": \"1\", \"ja\": \"1\", \"ko\": \"1\", \"mn\": \"1\", \"ru\": \"1\", \"th\": \"1\", \"vi\": \"1\", \"zh\": \"1\"}', '{\"ar\": \"المستوى 1 (3.0)\", \"bg\": \"Ниво 1 (3.0)\", \"cn\": \"一级 (3.0)\", \"en\": \"Level 1 (3.0)\", \"fr\": \"Niveau 1 (3.0)\", \"ja\": \"3級 (3.0)\", \"ko\": \"Level 1 (3.0)\", \"mn\": \"1-р түвшин (3.0)\", \"ru\": \"Уровень 1 (3.0)\", \"th\": \"ระดับ 1 (3.0)\", \"vi\": \"Cấp độ 1 (3.0)\", \"zh\": \"一级 (3.0)\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828638', '{\"zh\":\"通过 HSK(一级)的考生可以理解并使用一些非常简单的汉语词语和句子，满足具体的交际需求，具备进一步学习汉语的能力。\",\"cn\":\"通过 HSK(一级)的考生可以理解并使用一些非常简单的汉语词语和句子，满足具体的交际需求，具备进一步学习汉语的能力。\",\"en\":\"Candidates who pass the HSK Level 1 exam can understand and use some very simple Chinese words and sentences to meet specific communication needs, and are able to take the next step in their Chinese studies.\"}', '描述文本未提供', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 0, '2025-06-10 16:42:27', '2025-06-10 16:42:27', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (32, 2, 4, 'New-HSK', 'New HSK2', '{\"ar\": \"2\", \"bg\": \"2\", \"cn\": \"2\", \"en\": \"2\", \"fr\": \"2\", \"ja\": \"2\", \"ko\": \"2\", \"mn\": \"2\", \"ru\": \"2\", \"th\": \"2\", \"vi\": \"2\", \"zh\": \"2\"}', '{\"ar\": \"المستوى 2 (3.0)\", \"bg\": \"Ниво 2 (3.0)\", \"cn\": \"二级 (3.0)\", \"en\": \"Level 2 (3.0)\", \"fr\": \"Niveau 2 (3.0)\", \"ja\": \"3級 (3.0)\", \"ko\": \"Level 2 (3.0)\", \"mn\": \"2-р түвшин (3.0)\", \"ru\": \"Уровень 2 (3.0)\", \"th\": \"ระดับ 2 (3.0)\", \"vi\": \"Cấp độ 2 (3.0)\", \"zh\": \"二级 (3.0)\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828638', '{\"zh\":\"通过 HSK(二级)的考生可以用汉语就熟悉的日常话题进行简单而直接的交流，达到初级汉语优等水平。 \",\"cn\":\"通过 HSK(二级)的考生可以用汉语就熟悉的日常话题进行简单而直接的交流，达到初级汉语优等水平。 \",\"en\":\"Candidates who pass the HSK Level 2 exam can communicate simply and directly in Chinese on familiar everyday topics, having reached an advanced level in elementary Chinese.\"}', '描述文本未提供', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 0, '2025-06-10 16:42:27', '2025-06-10 16:42:27', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (33, 3, 4, 'New-HSK', 'New HSK3', '{\"ar\": \"3\", \"bg\": \"3\", \"cn\": \"3\", \"en\": \"3\", \"fr\": \"3\", \"ja\": \"3\", \"ko\": \"3\", \"mn\": \"3\", \"ru\": \"3\", \"th\": \"3\", \"vi\": \"3\", \"zh\": \"3\"}', '{\"ar\": \"المستوى 3 (3.0)\", \"bg\": \"Ниво 3 (3.0)\", \"cn\": \"三级 (3.0)\", \"en\": \"Level 3 (3.0)\", \"fr\": \"Niveau 3 (3.0)\", \"ja\": \"3級 (3.0)\", \"ko\": \"Level 3 (3.0)\", \"mn\": \"3-р түвшин (3.0)\", \"ru\": \"Уровень 3 (3.0)\", \"th\": \"ระดับ 3 (3.0)\", \"vi\": \"Cấp độ 3 (3.0)\", \"zh\": \"三级 (3.0)\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828638', '{\"zh\":\"通过 HSK(三级)的考生可以用汉语完成生活、学习、工作等方面的基本交际任务，在中国旅游时，可应对遇到的大部分交际任务。\",\"cn\":\"通过 HSK(三级)的考生可以用汉语完成生活、学习、工作等方面的基本交际任务，在中国旅游时，可应对遇到的大部分交际任务。\",\"en\":\"Candidates who pass the HSK Level 3 exam can use Chinese to complete basic communication tasks in everyday life and in their studies, and can deal with most of the communication tasks encountered when travelling in China.\"}', '描述文本未提供', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 1, '2025-06-10 16:42:27', '2025-06-10 16:42:27', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (34, 4, 4, 'New-HSK', 'New HSK4', '{\"ar\": \"4\", \"bg\": \"4\", \"cn\": \"4\", \"en\": \"4\", \"fr\": \"4\", \"ja\": \"4\", \"ko\": \"4\", \"mn\": \"4\", \"ru\": \"4\", \"th\": \"4\", \"vi\": \"4\", \"zh\": \"4\"}', '{\"ar\": \"المستوى 4 (3.0)\", \"bg\": \"Ниво 4 (3.0)\", \"cn\": \"四级 (3.0)\", \"en\": \"Level 4 (3.0)\", \"fr\": \"Niveau 4 (3.0)\", \"ja\": \"4級 (3.0)\", \"ko\": \"Level 4 (3.0)\", \"mn\": \"4-р түвшин (3.0)\", \"ru\": \"Уровень 4 (3.0)\", \"th\": \"ระดับ 4 (3.0)\", \"vi\": \"Cấp độ 4 (3.0)\", \"zh\": \"四级 (3.0)\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828638', '{\"zh\":\"通过 HSK(四级)的考生可以用汉语就较广泛领域的话题进行谈论，比较流利地与汉语为母语者进行交流。 \",\"cn\":\"通过 HSK(四级)的考生可以用汉语就较广泛领域的话题进行谈论，比较流利地与汉语为母语者进行交流。 \",\"en\":\"Candidates who pass the HSK Level 4 exam can talk in Chinese on a wider range of topics and communicate relatively fluently with native speakers of Chinese.\"}', '描述文本未提供', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 1, '2025-06-10 16:42:27', '2025-06-10 16:42:27', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (35, 5, 4, 'New-HSK', 'New HSK5', '{\"ar\": \"5\", \"bg\": \"5\", \"cn\": \"5\", \"en\": \"5\", \"fr\": \"5\", \"ja\": \"5\", \"ko\": \"5\", \"mn\": \"5\", \"ru\": \"5\", \"th\": \"5\", \"vi\": \"5\", \"zh\": \"5\"}', '{\"ar\": \"المستوى 5 (3.0)\", \"bg\": \"Ниво 5 (3.0)\", \"cn\": \"五级 (3.0)\", \"en\": \"Level 5 (3.0)\", \"fr\": \"Niveau 5 (3.0)\", \"ja\": \"5級 (3.0)\", \"ko\": \"Level 5 (3.0)\", \"mn\": \"5-р түвшин (3.0)\", \"ru\": \"Уровень 5 (3.0)\", \"th\": \"ระดับ 5 (3.0)\", \"vi\": \"Cấp độ 5 (3.0)\", \"zh\": \"五级 (3.0)\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828638', '{\"zh\":\"通过 HSK(五级)的考生可以阅读汉语报刊杂志，欣赏汉语影视节目，用汉语进行较为完整的演讲。\",\"cn\":\"通过 HSK(五级)的考生可以阅读汉语报刊杂志，欣赏汉语影视节目，用汉语进行较为完整的演讲。\",\"en\":\"Candidates who pass the HSK Level 5 exam can read Chinese newspapers and magazines, enjoy Chinese films and television programs, and give more complete speeches in Chinese.\"}', '描述文本未提供', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 1, '2025-06-10 16:42:27', '2025-06-10 16:42:27', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (36, 6, 4, 'New-HSK', 'New HSK6', '{\"ar\": \"6\", \"bg\": \"6\", \"cn\": \"6\", \"en\": \"6\", \"fr\": \"6\", \"ja\": \"6\", \"ko\": \"6\", \"mn\": \"6\", \"ru\": \"6\", \"th\": \"6\", \"vi\": \"6\", \"zh\": \"6\"}', '{\"ar\": \"المستوى 6 (3.0)\", \"bg\": \"Ниво 6 (3.0)\", \"cn\": \"六级 (3.0)\", \"en\": \"Level 6 (3.0)\", \"fr\": \"Niveau 6 (3.0)\", \"ja\": \"6級 (3.0)\", \"ko\": \"Level 6 (3.0)\", \"mn\": \"6-р түвшин (3.0)\", \"ru\": \"Уровень 6 (3.0)\", \"th\": \"ระดับ 6 (3.0)\", \"vi\": \"Cấp độ 6 (3.0)\", \"zh\": \"六级 (3.0)\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828638', '{\"zh\":\"通过 HSK(六级)的考生可以轻松地理解听到或读到的汉语信息，以口头或书面的形式用汉语流利地表达自己的见解。\",\"cn\":\"通过 HSK(六级)的考生可以轻松地理解听到或读到的汉语信息，以口头或书面的形式用汉语流利地表达自己的见解。\",\"en\":\"Candidates who pass the HSK Level 6 exam can easily understand information they hear or read in Chinese, and can express their opinions in Chinese fluently either orally or in writing.\"}', '描述文本未提供', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 1, '2025-06-10 16:42:27', '2025-06-10 16:42:27', 1, 1, NULL, 1);
INSERT INTO `mock_levels` VALUES (37, 7, 4, 'New-HSK', 'New HSK7-9', '{\"ar\": \"7-9\", \"bg\": \"7-9\", \"cn\": \"7-9\", \"en\": \"7-9\", \"fr\": \"7-9\", \"ja\": \"7-9\", \"ko\": \"7-9\", \"mn\": \"7-9\", \"ru\": \"7-9\", \"th\": \"7-9\", \"vi\": \"7-9\", \"zh\": \"7-9\"}', '{\"ar\": \"المستوى 7-9\", \"bg\": \"Ниво 7-9\", \"cn\": \"七-九级\", \"en\": \"Level 7-9\", \"fr\": \"Niveau 7-9\", \"ja\": \"7-9級\", \"ko\": \"Level 7-9\", \"mn\": \"7-9-р түвшин\", \"ru\": \"Уровень 7-9\", \"th\": \"ระดับ 7-9\", \"vi\": \"Cấp độ 7-9\", \"zh\": \"七-九级\"}', 'http://www.chinesetest.cn/gosign.do?id=2&lid=828638', '{\"zh\":\"通过HSK（七级）的考生具备良好的听、说、读、写能力和初步的专业翻译能力。能够就较为广泛和较高层次的话题进行基本、规范、流利、得体的社会交际。通过HSK（八级）的考生具备良好的听、说、读、写能力和基本的专业翻译能力。能够就各类高层次或专业话题进行较为规范、流利、得体的社会交际。通过HSK（九级）的考生具备良好的听、说、读、写能力和专业翻译能力。能够综合运用各种技能，在各种情境下，就各类话题进行规范、流利、得体的社会交际。\",\"cn\":\"通过HSK（七级）的考生具备良好的听、说、读、写能力和初步的专业翻译能力。能够就较为广泛和较高层次的话题进行基本、规范、流利、得体的社会交际。通过HSK（八级）的考生具备良好的听、说、读、写能力和基本的专业翻译能力。能够就各类高层次或专业话题进行较为规范、流利、得体的社会交际。通过HSK（九级）的考生具备良好的听、说、读、写能力和专业翻译能力。能够综合运用各种技能，在各种情境下，就各类话题进行规范、流利、得体的社会交际。\",\"en\":\"Candidates who pass HSK Level 7 possess good listening, speaking, reading, and writing abilities, as well as preliminary professional translation skills. They are capable of engaging in basic, standardized, fluent, and appropriate social interactions on relatively broad and high-level topics.Candidates who pass HSK Level 8 possess good listening, speaking, reading, and writing abilities, as well as basic professional translation skills. They can engage in relatively standardized, fluent, and appropriate social interactions on various high-level or professional topics.Candidates who pass HSK Level 9 possess good listening, speaking, reading, and writing abilities, as well as professional translation skills. They are capable of integrating various skills and engaging in standardized, fluent, and appropriate social interactions on various topics in different contexts.\"}', 'hsk7-9', NULL, 'https://staging-public.hskmock.com/yct-examination/start.mp3', 0, 1, '2021-05-19 15:15:39', '2021-05-19 15:15:39', 1, 1, NULL, 2);
INSERT INTO `mock_levels` VALUES (43, 1, 5, 'New-HSKK', 'HSK (Level 3) Speaking', '{\"ar\": \"3\", \"bg\": \"3\", \"cn\": \"3\", \"en\": \"3\", \"fr\": \"3\", \"ja\": \"3\", \"ko\": \"3\", \"mn\": \"3\", \"ru\": \"3\", \"th\": \"3\", \"vi\": \"3\", \"zh\": \"3\"}', '{\"ar\": \"المستوى 3\", \"bg\": \"Ниво 3\", \"cn\": \"三级\", \"en\": \"Level 3\", \"fr\": \"Niveau 3\", \"ja\": \"3級\", \"ko\": \"Level 3\", \"mn\": \"3-р түвшин\", \"ru\": \"Уровень 3\", \"th\": \"ระดับ 3\", \"vi\": \"Cấp độ 3\", \"zh\": \"三级\"}', NULL, NULL, '待补充cn_desc', NULL, 'https://staging-public.hskmock.com/hsk-examination/new-hskk-3/hskk1_2_3.mp3', 0, 1, '2026-01-05 19:30:48', '2026-01-05 19:30:48', 1, 1, 15, 1);
INSERT INTO `mock_levels` VALUES (44, 2, 5, 'New-HSKK', 'HSK (Level 4) Speaking', '{\"ar\": \"4\", \"bg\": \"4\", \"cn\": \"4\", \"en\": \"4\", \"fr\": \"4\", \"ja\": \"4\", \"ko\": \"4\", \"mn\": \"4\", \"ru\": \"4\", \"th\": \"4\", \"vi\": \"4\", \"zh\": \"4\"}', '{\"ar\": \"المستوى 4\", \"bg\": \"Ниво 4\", \"cn\": \"四级\", \"en\": \"Level 4\", \"fr\": \"Niveau 4\", \"ja\": \"4級\", \"ko\": \"Level 4\", \"mn\": \"4-р түвшин\", \"ru\": \"Уровень 4\", \"th\": \"ระดับ 4\", \"vi\": \"Cấp độ 4\", \"zh\": \"四级\"}', NULL, NULL, '待补充cn_desc', NULL, 'https://staging-public.hskmock.com/hsk-examination/new-hskk-4/hskk1_2_3.mp3', 0, 1, '2026-01-05 19:30:48', '2026-01-05 19:30:48', 1, 1, 20, 1);
INSERT INTO `mock_levels` VALUES (45, 3, 5, 'New-HSKK', 'HSK (Level 5) Speaking', '{\"ar\": \"5\", \"bg\": \"5\", \"cn\": \"5\", \"en\": \"5\", \"fr\": \"5\", \"ja\": \"5\", \"ko\": \"5\", \"mn\": \"5\", \"ru\": \"5\", \"th\": \"5\", \"vi\": \"5\", \"zh\": \"5\"}', '{\"ar\": \"المستوى 5\", \"bg\": \"Ниво 5\", \"cn\": \"五级\", \"en\": \"Level 5\", \"fr\": \"Niveau 5\", \"ja\": \"5級\", \"ko\": \"Level 5\", \"mn\": \"5-р түвшин\", \"ru\": \"Уровень 5\", \"th\": \"ระดับ 5\", \"vi\": \"Cấp độ 5\", \"zh\": \"五级\"}', NULL, NULL, '待补充cn_desc', NULL, 'https://staging-public.hskmock.com/hsk-examination/new-hskk-5/hskk1_2_3.mp3', 0, 1, '2026-01-05 19:30:48', '2026-01-05 19:30:48', 1, 1, 23, 1);
INSERT INTO `mock_levels` VALUES (46, 4, 5, 'New-HSKK', 'HSK (Level 6) Speaking', '{\"ar\": \"6\", \"bg\": \"6\", \"cn\": \"6\", \"en\": \"6\", \"fr\": \"6\", \"ja\": \"5\", \"ko\": \"6\", \"mn\": \"6\", \"ru\": \"6\", \"th\": \"6\", \"vi\": \"6\", \"zh\": \"6\"}', '{\"ar\": \"المستوى 6\", \"bg\": \"Ниво 6\", \"cn\": \"六级\", \"en\": \"Level 6\", \"fr\": \"Niveau 6\", \"ja\": \"6級\", \"ko\": \"Level 6\", \"mn\": \"6-р түвшин\", \"ru\": \"Уровень 6\", \"th\": \"ระดับ 6\", \"vi\": \"Cấp độ 6\", \"zh\": \"六级\"}', NULL, NULL, '待补充cn_desc', NULL, 'https://staging-public.hskmock.com/hsk-examination/new-hskk-6/hskk1_2_3.mp3', 0, 1, '2026-01-05 19:30:48', '2026-01-05 19:30:48', 1, 1, 23, 1);
