-- ----------------------------
-- Table structure for mock_examination_paper
-- ----------------------------
DROP TABLE IF EXISTS `mock_examination_paper`;
CREATE TABLE `mock_examination_paper`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'id 主键',
  `level_id` bigint(20) NULL DEFAULT NULL COMMENT 'HSK等级',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '试卷名称',
  `name_trans` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '试卷名称国际化',
  `score_full` int(11) NULL DEFAULT NULL COMMENT '满分',
  `seq` int(11) NULL DEFAULT NULL COMMENT '试卷顺序',
  `explain_audio` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '说明音频',
  `time_full` int(11) NULL DEFAULT NULL COMMENT '考试时长',
  `listen_review_duration` int(11) NULL DEFAULT NULL COMMENT '听力结束后回顾时间',
  `time_sheet` int(11) NULL DEFAULT NULL COMMENT '答题卡时间',
  `icon_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '图标路径',
  `resource_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '资源包路径',
  `version` int(11) NULL DEFAULT NULL COMMENT '资源版本号',
  `delete_flag` tinyint(1) NULL DEFAULT 0 COMMENT '是否删除 0 未删除 1 已删除',
  `mock_type` int(11) NULL DEFAULT 1 COMMENT '1 hsk 2 hskk 3 yct',
  `product_base_id` int(11) NOT NULL COMMENT '学习需要付的元商品',
  `credit` int(11) NOT NULL COMMENT '所需元商品数量',
  `buy_product_id` int(11) NULL DEFAULT NULL COMMENT '当付费券不足时, 需要购买此商品',
  `create_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '试卷状态 0 未发布 1 发布 2 下架',
  `member_resource` tinyint(4) NOT NULL DEFAULT 1 COMMENT '0 非会员资源1 会员资源',
  `paper_type` tinyint(4) NOT NULL DEFAULT 1 COMMENT '1 模拟考试卷 2 在线练习试卷',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 206 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'HSK考卷 保存HSK模拟考试试卷信息' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of mock_examination_paper
-- ----------------------------

-- ----------------------------
-- Table structure for mock_examination_part
-- ----------------------------
DROP TABLE IF EXISTS `mock_examination_part`;
CREATE TABLE `mock_examination_part`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'id主键',
  `code` int(11) NULL DEFAULT NULL COMMENT '部分编号',
  `segment_id` bigint(20) NULL DEFAULT NULL COMMENT '环节id',
  `question_count` int(11) NULL DEFAULT NULL COMMENT '题目数量',
  `objective_question_count` int(11) NULL DEFAULT NULL COMMENT '客观题数量',
  `subjective_question_count` int(11) NULL DEFAULT NULL COMMENT '主观题数量',
  `question_score` float NULL DEFAULT NULL COMMENT '每个题目得分',
  `part_score` float NULL DEFAULT NULL COMMENT '该题型分数',
  `answer_time` int(11) NULL DEFAULT NULL COMMENT '每个题型的回答时间',
  `part_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '只用于hskk',
  `part_name_trans` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '部分名称多语言',
  `delete_flag` tinyint(1) NULL DEFAULT 0 COMMENT '是否删除',
  `create_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 180 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of mock_examination_part
-- ----------------------------

-- ----------------------------
-- Table structure for mock_examination_segment
-- ----------------------------
DROP TABLE IF EXISTS `mock_examination_segment`;
CREATE TABLE `mock_examination_segment`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'id 主键',
  `level_id` bigint(20) NULL DEFAULT NULL COMMENT 'HSK等级ID',
  `segment_code` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '环节编码',
  `segment_name` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '环节名称',
  `segment_name_trans` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '环节名称国际化',
  `segment_desc` json NULL COMMENT 'segment说明',
  `score_full` int(11) NULL DEFAULT NULL COMMENT '环节满分',
  `question_count` int(11) NULL DEFAULT NULL COMMENT '题目数量',
  `duration` int(11) NULL DEFAULT NULL COMMENT '环节时长 分钟数',
  `seq` int(11) NULL DEFAULT NULL COMMENT '顺序号',
  `delete_flag` tinyint(1) NULL DEFAULT 0 COMMENT '是否删除',
  `create_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 60 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '试卷环节表 用于保存试卷与环节之间的关系' ROW_FORMAT = Dynamic;

