-- ----------------------------
-- Table structure for mock_levels
-- ----------------------------
DROP TABLE IF EXISTS `mock_levels`;
CREATE TABLE `mock_levels`  (
  `id` bigint(20) NOT NULL DEFAULT 0 COMMENT '主键',
  `level_id` int(11) NOT NULL DEFAULT 1 COMMENT '在指定类型下的等级',
  `level_type` int(11) NOT NULL DEFAULT 1 COMMENT '等级类型 （1 hsk 2 hskk 3 yct）',
  `type_name` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '类型名称',
  `level_name` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'hsk等级名称',
  `app_level_name` json NULL COMMENT 'app专用等级名称',
  `level_name_trans` json NULL COMMENT '等级名称多语言',
  `sign_up_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '报名地址',
  `level_desc` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '等级简介',
  `cn_desc` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '中文等级描述',
  `en_desc` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '英文等级描述',
  `level_explain_audio` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '模拟考试音音频地址',
  `delete_flag` tinyint(1) NULL DEFAULT 0 COMMENT '逻辑删除标识',
  `mark_flag` tinyint(1) NULL DEFAULT 0 COMMENT '是否需要批改',
  `create_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `exam_show_status` tinyint(1) NULL DEFAULT NULL COMMENT '模拟考显示状态，0表示不显示，1表示显示',
  `homework_show_status` tinyint(1) NULL DEFAULT NULL COMMENT '作业显示状态，0表示不显示，1表示显示',
  `paper_answer_time` int(11) NULL DEFAULT NULL COMMENT '该等级下试卷作答时间',
  `resource_type` int(11) NOT NULL DEFAULT 1 COMMENT '1：考试列表 2：文件资源列表',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'hsk等级表 ' ROW_FORMAT = Dynamic;

